const WebGPUShaderInfo& get_webgpu_shader_info(std::string_view name) {
  for (const auto& shader : kShaderRegistry) {
    if (shader.name == name) {
      return shader;
    }
  }
  throw std::runtime_error(
      "WebGPU shader registry: unknown shader '" + std::string(name) + "'");
}

